/*========================================================
  CREAR TABLA CAT_PAIS
========================================================*/
BEGIN
   EXECUTE IMMEDIATE 'DROP TABLE CAT_PAIS CASCADE CONSTRAINTS';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/


CREATE TABLE CAT_PAIS (
    UUID_PAIS VARCHAR2(36)  NOT NULL,
    CODIGO VARCHAR2(5),
    DESCRIPCION VARCHAR2(255),
    ESTADO NUMBER(2) NOT NULL,
    FECHA_CREACION TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CREADO_POR VARCHAR2(36) NOT NULL,
    FECHA_ACTUALIZACION TIMESTAMP ,
    ACTUALIZADO_POR VARCHAR2(36),
    NOTAS VARCHAR2(100),

    CONSTRAINT PK_CAT_PAIS PRIMARY KEY (UUID_PAIS),

    CONSTRAINT CK_CAT_PAIS_ESTADO
        CHECK (ESTADO IN (0, 99))
);

COMMENT ON TABLE CAT_PAIS IS 'Catálogo de países';
COMMENT ON COLUMN CAT_PAIS.UUID_PAIS IS 'Identificador único UUID';
COMMENT ON COLUMN CAT_PAIS.CODIGO IS 'Código del país';
COMMENT ON COLUMN CAT_PAIS.DESCRIPCION IS 'Nombre o descripción del país';
COMMENT ON COLUMN CAT_PAIS.ESTADO IS '0 = Inactivo, 99 = Activo';
COMMENT ON COLUMN CAT_PAIS.FECHA_CREACION IS 'Fecha de creación';
COMMENT ON COLUMN CAT_PAIS.CREADO_POR IS 'Usuario creador';
COMMENT ON COLUMN CAT_PAIS.FECHA_ACTUALIZACION IS 'Fecha de actualización';
COMMENT ON COLUMN CAT_PAIS.ACTUALIZADO_POR IS 'Usuario que actualizó';
COMMENT ON COLUMN CAT_PAIS.NOTAS IS 'Observaciones adicionales';

COMMIT;

select * from CAT_PAIS;

commit;
commit;

